class Solution {
    public int findTheLongestSubstring(String s) {
        int maxLen = 0;
        int[] vowelCount = new int[5];
        for (int i = 0, j = 0; j < s.length(); j++) {
            if (s.charAt(j) == 'a') vowelCount[0]++;
            else if (s.charAt(j) == 'e') vowelCount[1]++;
            else if (s.charAt(j) == 'i') vowelCount[2]++;
            else if (s.charAt(j) == 'o') vowelCount[3]++;
            else if (s.charAt(j) == 'u') vowelCount[4]++;
            while (!isValid(vowelCount)) {
                if (s.charAt(i) == 'a') vowelCount[0]--;
                else if (s.charAt(i) == 'e') vowelCount[1]--;
                else if (s.charAt(i) == 'i') vowelCount[2]--;
                else if (s.charAt(i) == 'o') vowelCount[3]--;
                else if (s.charAt(i) == 'u') vowelCount[4]--;
                i++;
            }
            maxLen = Math.max(maxLen, j - i + 1);
        }
        return maxLen;
    }
    private boolean isValid(int[] vowelCount) {
        for (int count : vowelCount) {
            if (count % 2 != 0) {
                return false;
            }
        }
        return true;
    }
}
